import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const LoginPage = () => {
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleLogin = (e) => {
    e.preventDefault();
    setLoading(true);
    setTimeout(() => navigate('/dashboard'), 1500);
  };

  return (
    <div style={styles.container}>
      {/* 🚀 THE BACKGROUND PATTERNS FROM THE IMAGE */}
      <div style={styles.bgCircuitTop}></div>
      <div style={styles.bgCircuitBottom}></div>

      {/* "Go to Homepage" Top Left Button */}
      <div style={styles.homepageBtnContainer}>
        <button style={styles.homepageBtn}>
          <span style={{ marginRight: '8px' }}>←</span> Go to Homepage
        </button>
      </div>

      <div style={styles.card}>
        <div style={styles.header}>
          <h1 style={styles.title}>Welcome Back</h1>
          <p style={styles.subtitle}>Please login to your account</p>
        </div>

        <form onSubmit={handleLogin} style={styles.form}>
          <div style={styles.inputGroup}>
            <label style={styles.label}>Email</label>
            <input 
              type="email" 
              placeholder="Enter your email" 
              style={styles.input} 
              required 
            />
          </div>

          <div style={styles.inputGroup}>
            <label style={styles.label}>Password</label>
            <div style={styles.passwordWrapper}>
              <input 
                type="password" 
                placeholder="Enter your password" 
                style={styles.inputPassword} 
                required 
              />
              <span style={styles.passwordArrow}>→</span>
            </div>
          </div>

          <div style={styles.options}>
            <label style={styles.remember}>
              <input type="checkbox" style={{ marginRight: '8px' }} /> Remember me
            </label>
            <span style={styles.forgot}>Forgot Password</span>
          </div>

          <button type="submit" style={styles.loginBtn}>
            {loading ? 'Initializing...' : 'Login'}
          </button>
        </form>

        <div style={styles.divider}>
          <span style={styles.dividerLine}></span>
          <span style={styles.dividerText}>or</span>
          <span style={styles.dividerLine}></span>
        </div>

        {/* 🛠️ SOCIAL LOGIN STACK FROM THE IMAGE */}
        <div style={styles.socialGroup}>
          <button style={styles.socialBtn}>
            <img src="https://img.icons8.com/color/24/000000/google-logo.png" alt="G" /> Login With Google
          </button>
          <button style={styles.socialBtn}>
            <img src="https://img.icons8.com/ios-filled/24/3f51b5/facebook-new.png" alt="F" style={{ filter: 'brightness(1.5)' }} /> Login With Facebook
          </button>
          <button style={styles.socialBtn}>
            <img src="https://img.icons8.com/ios-filled/24/ffffff/mac-os.png" alt="A" /> Login With Apple ID
          </button>
        </div>

        <div style={styles.footer}>
          Dont have an Account? 
          <span style={styles.toggle}> Sign Up</span>
        </div>
      </div>
    </div>
  );
};

const styles = {
  container: {
    backgroundColor: '#11151c', // Dark background from image
    height: '100vh',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    fontFamily: "'Inter', sans-serif",
    position: 'relative',
    overflow: 'hidden'
  },
  // 🔥 Circuit patterns placed correctly
  bgCircuitTop: {
    position: 'absolute',
    width: '40%', height: '40%',
    top: '5%', right: '5%',
    backgroundImage: 'url("https://www.transparenttextures.com/patterns/circuit-board.png")',
    opacity: 0.15, zIndex: 0,
    filter: 'invert(1)' // Make it light-colored on dark bg
  },
  bgCircuitBottom: {
    position: 'absolute',
    width: '40%', height: '40%',
    bottom: '10%', left: '5%',
    backgroundImage: 'url("https://www.transparenttextures.com/patterns/circuit-board.png")',
    opacity: 0.15, zIndex: 0,
    filter: 'invert(1)' // Make it light-colored on dark bg
  },
  homepageBtnContainer: {
    position: 'absolute', top: '30px', left: '30px', zIndex: 10
  },
  homepageBtn: {
    background: 'transparent', border: '1px solid #475569',
    color: '#cbd5e1', padding: '8px 18px',
    borderRadius: '20px', cursor: 'pointer',
    fontSize: '13px', display: 'flex', alignItems: 'center'
  },
  card: {
    width: '440px',
    backgroundColor: 'rgba(28, 33, 44, 0.9)', // Semi-transparent card
    backdropFilter: 'blur(10px)',
    borderRadius: '24px',
    padding: '50px 45px',
    boxShadow: '0 25px 60px rgba(0,0,0,0.6)',
    zIndex: 5,
    border: '1px solid #2d3544'
  },
  header: { textAlign: 'left', marginBottom: '35px' },
  title: { color: '#ffffff', fontSize: '30px', margin: '0 0 10px 0', fontWeight: 'bold' },
  subtitle: { color: '#94a3b8', fontSize: '15px' },
  inputGroup: { marginBottom: '25px' },
  label: { display: 'block', color: '#cbd5e1', fontSize: '14px', marginBottom: '10px', fontWeight: '500' },
  input: {
    width: '100%', padding: '15px',
    backgroundColor: '#2d3544', border: '1px solid #3f4a5d',
    borderRadius: '12px', color: 'white', outline: 'none',
    boxSizing: 'border-box', fontSize: '14px'
  },
  // 🛠️ Password field with inner arrow icon
  passwordWrapper: { position: 'relative' },
  inputPassword: {
    width: '100%', padding: '15px', paddingRight: '45px', // Make room for arrow
    backgroundColor: '#2d3544', border: '1px solid #3f4a5d',
    borderRadius: '12px', color: 'white', outline: 'none',
    boxSizing: 'border-box', fontSize: '14px'
  },
  passwordArrow: {
    position: 'absolute', right: '15px', top: '50%',
    transform: 'translateY(-50%)', color: '#6366f1',
    fontSize: '20px', cursor: 'pointer'
  },
  options: {
    display: 'flex', justifyContent: 'space-between',
    fontSize: '13px', color: '#94a3b8', marginBottom: '25px',
    alignItems: 'center'
  },
  remember: { display: 'flex', alignItems: 'center', cursor: 'pointer' },
  forgot: { color: '#94a3b8', cursor: 'pointer', borderBottom: '1px solid transparent', transition: '0.3s' },
  // 🔥 Match the Blue Button Color
  loginBtn: {
    width: '100%', padding: '16px',
    backgroundColor: '#5d5fef', // Specific purple/blue from image
    color: 'white', border: 'none',
    borderRadius: '12px', fontWeight: '600',
    cursor: 'pointer', fontSize: '15px', transition: '0.3s'
  },
  // 🛠️ Divider style from the image
  divider: {
    textAlign: 'center', color: '#475569',
    margin: '30px 0', fontSize: '13px',
    display: 'flex', alignItems: 'center'
  },
  dividerLine: { flex: 1, height: '1px', backgroundColor: '#334155' },
  dividerText: { padding: '0 15px' },
  // 🛠️ Social Login Stack from the image
  socialGroup: { display: 'flex', flexDirection: 'column', gap: '15px' },
  socialBtn: {
    display: 'flex', alignItems: 'center',
    justifyContent: 'center', gap: '12px',
    width: '100%', padding: '14px',
    backgroundColor: 'transparent', border: '1px solid #3f4a5d',
    borderRadius: '12px', color: 'white',
    cursor: 'pointer', fontSize: '15px'
  },
  footer: { textAlign: 'center', marginTop: '30px', color: '#94a3b8', fontSize: '14px' },
  toggle: { color: '#6366f1', fontWeight: '600', cursor: 'pointer' }
};

export default LoginPage;
